1	type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	type QuoteStep = { op: "quote"; items: Item[] };
8	type Damage = { itemType: string; amount: number };
9	type Incident = { cause?: string; damages: Damage[] };
10	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
11	type Step = QuoteStep | ClaimStep;
12	type Customer = { yearsWithMHPCO: number };
13	type Scenario = { customer: Customer; steps: Step[] };
14	type QuoteResult = { premium: number };
15	type ClaimResult = { payout: number; remainingCap: number };
16	type StepResult = QuoteResult | ClaimResult;
17	
18	const PROCESSING_FEE = 5;
19	const FIRST_INSURANCE_RATE = 0.1;
20	const CURSE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const LOYALTY_RATE = 0.2;
24	const LOYALTY_THRESHOLD = 2;
25	const FOLLOWUP_RATE = 0.15;
26	const COMPONENT_BASE_PREMIUM = 25;
27	const COMPONENT_INSURANCE_VALUE = 250;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE_PREMIUM = 60;
30	const DEDUCTIBLE = 100;
31	const CAP_MULTIPLIER = 2;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	};
39	
40	const INSURANCE_VALUES: Record<string, number> = {
41	  sword: 1000,
42	  amulet: 600,
43	  staff: 800,
44	  potion: 400,
45	};
46	
47	const isComponent = (item: Item): boolean => BASE_PREMIUMS[item.type] === undefined;
48	
49	const componentGroupBase = (count: number): number =>
50	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * COMPONENT_BASE_PREMIUM;
51	
52	const countByType = (items: Item[]): Map<string, number> =>
53	  items.reduce(
54	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
55	    new Map<string, number>(),
56	  );
57	
58	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
59	const itemInsuranceValue = (item: Item): number =>
60	  isComponent(item) ? COMPONENT_INSURANCE_VALUE : INSURANCE_VALUES[item.type];
61	
62	const componentsBaseTotal = (components: Item[]): number =>
63	  [...countByType(components).values()].reduce(
64	    (sum, count) => sum + componentGroupBase(count),
65	    0,
66	  );
67	
68	const policyBase = (items: Item[]): number => {
69	  const mainBase = items.filter((i) => !isComponent(i)).reduce((sum, i) => sum + itemBasePremium(i), 0);
70	  const compBase = componentsBaseTotal(items.filter(isComponent));
71	  return mainBase + compBase;
72	};
73	
74	const insuranceSum = (items: Item[]): number =>
75	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
76	
77	const isCursed = (item: Item): boolean => item.cursed === true;
78	const isHighlyEnchanted = (item: Item): boolean =>
79	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
80	
81	const itemSurcharge = (item: Item): number => {
82	  if (isComponent(item)) return 0;
83	  const base = itemBasePremium(item);
84	  const rate = (isCursed(item) ? CURSE_RATE : 0) + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
85	  return base * rate;
86	};
87	
88	const itemSurchargesTotal = (items: Item[]): number =>
89	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
90	
91	const isLoyal = (customer: Customer): boolean => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
92	
93	const loyaltyDiscount = (base: number, customer: Customer): number =>
94	  isLoyal(customer) ? base * LOYALTY_RATE : 0;
95	
96	type Policy = {
97	  items: Item[];
98	  remainingCap: number;
99	};
100	
101	const computeQuote = (step: QuoteStep, customer: Customer, quoteIndex: number): QuoteResult => {
102	  const base = policyBase(step.items);
103	  const surcharges = itemSurchargesTotal(step.items);
104	  const firstInsurance = base * FIRST_INSURANCE_RATE;
105	  const loyalty = loyaltyDiscount(base, customer);
106	  const followup = quoteIndex > 0 ? base * FOLLOWUP_RATE : 0;
107	  const premium = Math.ceil(base + surcharges + firstInsurance - loyalty - followup) + PROCESSING_FEE;
108	  return { premium };
109	};
110	
111	const computeDamagePayout = (damage: Damage): number => {
112	  return Math.max(0, damage.amount - DEDUCTIBLE);
113	};
114	
115	const computeClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
116	  const policy = policies.get(step.policy)!;
117	  const grossPayout = step.incident.damages.reduce((sum, d) => sum + computeDamagePayout(d), 0);
118	  const payout = Math.min(grossPayout, policy.remainingCap);
119	  policy.remainingCap -= payout;
120	  return { payout, remainingCap: policy.remainingCap };
121	};
122	
123	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
124	  const policies = new Map<number, Policy>();
125	  let quoteIndex = 0;
126	  const results = scenario.steps.map((step, stepIndex) => {
127	    if (step.op === "quote") {
128	      const result = computeQuote(step, scenario.customer, quoteIndex);
129	      policies.set(stepIndex, {
130	        items: step.items,
131	        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
132	      });
133	      quoteIndex += 1;
134	      return result;
135	    }
136	    return computeClaim(step, policies);
137	  });
138	  return { results };
139	};
